import { MakeLogicType, actions, kea, listeners, path, reducers } from 'kea'
import { forms } from 'kea-forms'
import type { DeepPartial, DeepPartialMap, FieldName, ValidationErrorType } from 'kea-forms'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'

import { DataColorThemeModelPayload } from '~/types'

const PAYLOAD_DEFAULT: DataColorThemeModelPayload = { name: '', colors: [] }

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface dataColorThemesModalLogicValues {
    isOpen: boolean
    isThemeSubmitting: boolean
    isThemeValid: boolean
    showThemeErrors: boolean
    theme: DataColorThemeModelPayload
    themeAllErrors: Record<string, any>
    themeChanged: boolean
    themeErrors: DeepPartialMap<DataColorThemeModelPayload, ValidationErrorType>
    themeHasErrors: boolean
    themeManualErrors: Record<string, any>
    themeTouched: boolean
    themeTouches: Record<string, boolean>
    themeValidationErrors: DeepPartialMap<DataColorThemeModelPayload, ValidationErrorType>
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface dataColorThemesModalLogicActions {
    addColor: () => {
        value: true
    }
    closeModal: () => {
        value: true
    }
    duplicateColor: (index: number) => {
        index: number
    }
    openModal: (theme: any) => {
        theme: any
    }
    removeColor: (index: number) => {
        index: number
    }
    resetTheme: (values?: DataColorThemeModelPayload) => {
        values?: DataColorThemeModelPayload
    }
    setThemeManualErrors: (errors: Record<string, any>) => {
        errors: Record<string, any>
    }
    setThemeValue: (
        key: FieldName,
        value: any
    ) => {
        name: FieldName
        value: any
    }
    setThemeValues: (values: DeepPartial<DataColorThemeModelPayload>) => {
        values: DeepPartial<DataColorThemeModelPayload>
    }
    submitTheme: () => {
        value: boolean
    }
    submitThemeFailure: (
        error: Error,
        errors: Record<string, any>
    ) => {
        error: Error
        errors: Record<string, any>
    }
    submitThemeRequest: (theme: DataColorThemeModelPayload) => {
        theme: DataColorThemeModelPayload
    }
    submitThemeSuccess: (theme: DataColorThemeModelPayload) => {
        theme: DataColorThemeModelPayload
    }
    touchThemeField: (key: string) => {
        key: string
    }
}

export type dataColorThemesModalLogicType = MakeLogicType<
    dataColorThemesModalLogicValues,
    dataColorThemesModalLogicActions
>

export const dataColorThemesModalLogic = kea<dataColorThemesModalLogicType>([
    path(['scenes', 'settings', 'environment', 'dataColorThemesModalLogic']),
    actions({
        openModal: (theme) => ({ theme }),
        closeModal: true,
        addColor: true,
        duplicateColor: (index: number) => ({ index }),
        removeColor: (index: number) => ({ index }),
    }),
    reducers({
        isOpen: [
            false,
            {
                openModal: () => true,
                closeModal: () => false,
            },
        ],
        theme: [
            { name: '', colors: [] } as DataColorThemeModelPayload,
            {
                addColor: (theme) => ({
                    ...theme,
                    colors: [...(theme.colors || []), theme.colors[theme.colors.length - 1] || '#1d4aff'],
                }),
                duplicateColor: (theme, { index }) => ({
                    ...theme,
                    colors: theme.colors.flatMap((color, idx) => (idx === index ? [color, color] : [color])),
                }),
                removeColor: (theme, { index }) => ({
                    ...theme,
                    colors: theme.colors.filter((_, idx) => idx !== index),
                }),
            },
        ],
    }),
    forms(({ actions }) => ({
        theme: {
            defaults: PAYLOAD_DEFAULT,
            submit: async ({ id, name, colors }, breakpoint): Promise<DataColorThemeModelPayload> => {
                const payload: DataColorThemeModelPayload = {
                    name: name || '',
                    colors: colors || [],
                }

                breakpoint()

                try {
                    const updatedTheme = id
                        ? await api.dataColorThemes.update(id, payload)
                        : await api.dataColorThemes.create(payload)

                    lemonToast.success(updatedTheme ? 'Theme saved.' : 'Theme created.')
                    actions.closeModal()

                    return updatedTheme
                } catch (error: any) {
                    if (error.data?.attr && error.data?.detail) {
                        const field = error.data?.attr?.replace(/_/g, ' ')
                        lemonToast.error(`Error saving data color theme: ${field}: ${error.data.detail}`)
                    } else {
                        lemonToast.error(`Error saving data color theme`)
                    }
                }

                return payload
            },
            errors: (theme) => ({
                name: !theme?.name ? 'This field is required' : undefined,
            }),
        },
    })),
    listeners(({ actions }) => ({
        openModal: ({ theme }) => {
            actions.resetTheme(theme)
        },
    })),
])
